<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Models\Payroll\PayrollItem; use App\Services\Foundation\SchoolProfileService; use Illuminate\View\View; class PayslipController extends Controller{public function show(PayrollItem $item,SchoolProfileService $profiles):View{abort_unless(auth()->user()->can('payslips.view'),403); return view('payroll.payslips.show',['title'=>'Slip Gaji','item'=>$item->load('run.period','components','payments'),'profile'=>$profiles->current()]);} public function print(PayrollItem $item,SchoolProfileService $profiles):View{abort_unless(auth()->user()->can('payslips.print'),403); return view('payroll.payslips.print',['title'=>'Cetak Slip Gaji','item'=>$item->load('run.period','components','payments'),'profile'=>$profiles->current()]);}}
